```cpp
#include <bits/stdc++.h>
using namespace std;

int n;
const int N = 2e5 + 1;
char a[N];
int sum = 0;
int t[N];

bool check(int i)
{
    while(i <= n and i >= 1)
    {
        if(a[i] == '<') i --;//模拟
        if(a[i] == '>') i ++;//模拟
        if(t[i] == 1) return false;//防止死循环
    }
    return true;//如果掉出台面，返回true
}

int main()
{
    cin >> n;
    for(int i = 1; i <= n; i ++)
    {
        cin >> a[i];
    }
    for(int i = 1; i <= n; i ++)
    {
        if(a[i] == '<' and a[i - 1] == '>'){
            t[i] = 1;
            t[i - 1] = 1;
        }//统计'><'
    }
    for(int i = 1; i <= n; i ++)
    {
        if(t[i] == 1) continue;
        if(check(i)) sum ++;//如果可以使得小球调出台面，那么sum++
    }
    cout << sum << endl;
}
```

